### 5. Zustand Store (`orderDetail.store.ts`)

**Store Shape:**
```typescript
interface OrderDetailSlice {
  orderDetail: OrderDetailState;
  orderDetailActions: OrderDetailActions;
}

interface OrderDetailActions {
  setOrderDetailStatus: (status: OrderDetailStatus) => void;
  setOrderDetail: (orderDetail: PointsTransaction, transactionId?: string) => void;
  reset: () => void;
}
```

**Store Factory:**
```typescript
export const createOrderDetailSlice: StateCreator<OrderDetailSlice> = (set) => ({
  orderDetail: INITIAL_STATE,
  orderDetailActions: {
    setOrderDetailStatus: (status) => 
      set(state => ({ orderDetail: { ...state.orderDetail, status } })),

    setOrderDetail: (orderDetail, transactionId) =>
      set(state => ({
        orderDetail: {
          ...state.orderDetail,
          orderDetail,
          status: OrderDetailStatus.SUCCESS,
          error: undefined,
          transactionId,
        },
      })),

    reset: () => 
      set({ orderDetail: INITIAL_STATE }),
  },
});
```

